# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration backend that manages users, projects,
tasks, messages, performance metrics and reports.

The public surface (classes, enums, exceptions and ``TeamCollaborationManager``
methods) is exercised by ``test_solution.py``.  The module depends only on the
Python standard library and is ASCII only.
"""

import csv
import io
import json
import threading
from dataclasses import dataclass
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Roles a user may hold within the system."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Categories of reports the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime

    def clone(self) -> "Attachment":
        return Attachment(
            self.filename, self.size, self.uploaded_by, self.uploaded_at
        )


@dataclass
class User:
    """A registered user."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime

    def clone(self) -> "User":
        return User(
            self.id, self.username, self.email, self.role, self.created_at
        )


@dataclass
class Project:
    """A project owned by a user."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime

    def clone(self) -> "Project":
        return Project(
            self.id,
            self.name,
            self.description,
            self.start_date,
            self.end_date,
            self.owner_id,
            self.created_at,
        )


@dataclass
class Task:
    """A unit of work belonging to a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime

    def clone(self) -> "Task":
        return Task(
            self.id,
            self.project_id,
            self.title,
            self.status,
            self.assignee_id,
            self.deadline,
            self.started_at,
            self.completed_at,
            self.created_at,
        )


@dataclass
class Message:
    """A message posted to a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None

    def clone(self) -> "Message":
        return Message(
            self.id,
            self.author_id,
            self.body,
            self.project_id,
            self.task_id,
            self.parent_id,
            [a.clone() for a in self.attachments],
            self.created_at,
            self.edited_at,
        )


@dataclass
class Rating:
    """A peer rating from one user to another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: Optional[str]
    task_id: Optional[int]
    created_at: datetime

    def clone(self) -> "Rating":
        return Rating(
            self.id,
            self.rater_id,
            self.ratee_id,
            self.score,
            self.feedback,
            self.task_id,
            self.created_at,
        )


# ---------------------------------------------------------------------------
# Internal store
# ---------------------------------------------------------------------------
class _Store:
    """A thin, lock-sharing container for a single entity type.

    All stores share the manager's lock so that cross-store operations remain
    atomic; the shared ``_lock`` identity is part of the public contract.
    """

    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock
        self.items: Dict[int, object] = {}


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates users, projects, tasks, messaging, performance and reports.

    The manager is fully thread-safe: every mutating or reading operation is
    guarded by a single re-entrant lock that is shared with every sub-store.
    Identifiers are globally unique across all entity types and begin at 1.
    Getters return defensive copies so callers cannot mutate internal state.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._lock = threading.RLock()
        self._clock: Callable[[], datetime] = now if now is not None else datetime.now
        self._id_counter = 0

        # Sub-stores share the single lock (contract verified by tests).
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)
        self.reports = _Store(self._lock)

        # Secondary indices (guarded by the shared lock).
        self._username_index: Dict[str, int] = {}
        self._email_index: Dict[str, int] = {}
        self._tasks_by_project: Dict[int, set] = {}
        self._tasks_by_assignee: Dict[int, set] = {}
        self._messages_by_project: Dict[int, List[int]] = {}
        self._messages_by_task: Dict[int, List[int]] = {}
        self._ratings_by_ratee: Dict[int, List[int]] = {}

    # -- helpers ------------------------------------------------------------
    def _gen_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    def _now(self) -> datetime:
        return self._clock()

    def _require_user(self, user_id: int) -> User:
        user = self.users.items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user  # type: ignore[return-value]

    def _require_project(self, project_id: int) -> Project:
        project = self.projects.items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project  # type: ignore[return-value]

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks.items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task  # type: ignore[return-value]

    def _require_message(self, message_id: int) -> Message:
        message = self.messages.items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message  # type: ignore[return-value]

    @staticmethod
    def _valid_email(email: object) -> bool:
        return isinstance(email, str) and bool(email.strip()) and "@" in email

    @staticmethod
    def _non_empty(value: object) -> bool:
        return isinstance(value, str) and bool(value.strip())

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            if not self._non_empty(username):
                raise ValidationError("username is required")
            if not self._valid_email(email):
                raise ValidationError("a valid email is required")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username in self._username_index:
                raise DuplicateError("username already exists")
            if email in self._email_index:
                raise DuplicateError("email already exists")

            user_id = self._gen_id()
            user = User(user_id, username, email, role, self._now())
            self.users.items[user_id] = user
            self._username_index[username] = user_id
            self._email_index[email] = user_id
            return user.clone()

    def get_user(self, user_id) -> User:
        with self._lock:
            return self._require_user(user_id).clone()

    def list_users(self) -> List[User]:
        with self._lock:
            return [
                self.users.items[uid].clone()  # type: ignore[union-attr]
                for uid in sorted(self.users.items)
            ]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                if not self._non_empty(username):
                    raise ValidationError("username is required")
                existing = self._username_index.get(username)
                if existing is not None and existing != user_id:
                    raise DuplicateError("username already exists")
            if email is not None:
                if not self._valid_email(email):
                    raise ValidationError("a valid email is required")
                existing = self._email_index.get(email)
                if existing is not None and existing != user_id:
                    raise DuplicateError("email already exists")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None and username != user.username:
                del self._username_index[user.username]
                self._username_index[username] = user_id
                user.username = username
            if email is not None and email != user.email:
                del self._email_index[user.email]
                self._email_index[email] = user_id
                user.email = email
            if role is not None:
                user.role = role
            return user.clone()

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects.items.values():
                if project.owner_id == user_id:  # type: ignore[union-attr]
                    raise ConflictError("user owns a project")

            for task_id in self._tasks_by_assignee.get(user_id, set()):
                task = self.tasks.items.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task")

            del self.users.items[user_id]
            self._username_index.pop(user.username, None)
            self._email_index.pop(user.email, None)
            self._tasks_by_assignee.pop(user_id, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ) -> Project:
        with self._lock:
            if not self._non_empty(name):
                raise ValidationError("project name is required")
            self._require_user(owner_id)
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")

            project_id = self._gen_id()
            project = Project(
                project_id,
                name,
                description if description is not None else "",
                start_date,
                end_date,
                owner_id,
                self._now(),
            )
            self.projects.items[project_id] = project
            self._tasks_by_project.setdefault(project_id, set())
            self._messages_by_project.setdefault(project_id, [])
            return project.clone()

    def get_project(self, project_id) -> Project:
        with self._lock:
            return self._require_project(project_id).clone()

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                self.projects.items[pid].clone()  # type: ignore[union-attr]
                for pid in sorted(self.projects.items)
            ]

    def update_project(
        self,
        project_id,
        name=None,
        description=None,
        start_date=None,
        end_date=None,
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            if name is not None and not self._non_empty(name):
                raise ValidationError("project name is required")

            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")

            if name is not None:
                project.name = name
            if description is not None:
                project.description = description
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            return project.clone()

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._require_project(project_id)

            for task_id in list(self._tasks_by_project.get(project_id, set())):
                self._delete_task_internal(task_id)
            for message_id in list(self._messages_by_project.get(project_id, [])):
                self._delete_message_internal(message_id)

            self._tasks_by_project.pop(project_id, None)
            self._messages_by_project.pop(project_id, None)
            del self.projects.items[project_id]

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(
        self, project_id, title, assignee_id=None, deadline=None
    ) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            if not self._non_empty(title):
                raise ValidationError("task title is required")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")

            task_id = self._gen_id()
            task = Task(
                task_id,
                project_id,
                title,
                TaskStatus.NOT_STARTED,
                assignee_id,
                deadline,
                None,
                None,
                self._now(),
            )
            self.tasks.items[task_id] = task
            self._tasks_by_project.setdefault(project_id, set()).add(task_id)
            if assignee_id is not None:
                self._tasks_by_assignee.setdefault(assignee_id, set()).add(task_id)
            return task.clone()

    def get_task(self, task_id) -> Task:
        with self._lock:
            return self._require_task(task_id).clone()

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            task_ids = self._tasks_by_project.get(project_id, set())
            return [
                self.tasks.items[tid].clone()  # type: ignore[union-attr]
                for tid in sorted(task_ids)
            ]

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            self._require_user(assignee_id)
            task_ids = self._tasks_by_assignee.get(assignee_id, set())
            return [
                self.tasks.items[tid].clone()  # type: ignore[union-attr]
                for tid in sorted(task_ids)
            ]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return task.clone()

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return task.clone()

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return task.clone()

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects.items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return task.clone()

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None

            task.status = status
            return task.clone()

    def _set_assignee(self, task: Task, new_assignee_id: Optional[int]) -> None:
        old = task.assignee_id
        if old == new_assignee_id:
            return
        if old is not None:
            bucket = self._tasks_by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self._tasks_by_assignee.setdefault(new_assignee_id, set()).add(task.id)

    def _delete_task_internal(self, task_id: int) -> None:
        task = self.tasks.items.pop(task_id, None)
        if task is None:
            return
        if task.assignee_id is not None:  # type: ignore[union-attr]
            bucket = self._tasks_by_assignee.get(task.assignee_id)  # type: ignore[union-attr]
            if bucket is not None:
                bucket.discard(task_id)
        bucket = self._tasks_by_project.get(task.project_id)  # type: ignore[union-attr]
        if bucket is not None:
            bucket.discard(task_id)
        for message_id in list(self._messages_by_task.get(task_id, [])):
            self._delete_message_internal(message_id)
        self._messages_by_task.pop(task_id, None)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)

            raw_attachments = list(attachments) if attachments else []
            body_text = body if isinstance(body, str) else ("" if body is None else str(body))
            if not body_text.strip() and not raw_attachments:
                raise ValidationError("message body or attachment required")

            if parent_id is not None and parent_id not in self.messages.items:
                raise NotFoundError("parent message not found")

            now = self._now()
            attachment_objs = [
                Attachment(filename, len(data), author_id, now)
                for (filename, data) in raw_attachments
            ]

            message_id = self._gen_id()
            message = Message(
                message_id,
                author_id,
                body_text,
                project_id,
                task_id,
                parent_id,
                attachment_objs,
                now,
                None,
            )
            self.messages.items[message_id] = message
            if project_id is not None:
                self._messages_by_project.setdefault(project_id, []).append(message_id)
            if task_id is not None:
                self._messages_by_task.setdefault(task_id, []).append(message_id)
            return message.clone()

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            if not self._non_empty(new_body):
                raise ValidationError("message body is required")
            message.body = new_body
            message.edited_at = self._now()
            return message.clone()

    def add_attachment(self, message_id, uploader_id, filename, data) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach to a message"
                )
            if not self._non_empty(filename):
                raise ValidationError("filename is required")
            message.attachments.append(
                Attachment(filename, len(data), uploader_id, self._now())
            )
            return message.clone()

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            message_ids = self._messages_by_project.get(project_id, [])
            return [
                self.messages.items[mid].clone()  # type: ignore[union-attr]
                for mid in sorted(message_ids)
            ]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            message_ids = self._messages_by_task.get(task_id, [])
            return [
                self.messages.items[mid].clone()  # type: ignore[union-attr]
                for mid in sorted(message_ids)
            ]

    def delete_message(self, message_id, requester_id) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete a message")
            self._delete_message_internal(message_id)

    def _delete_message_internal(self, message_id: int) -> None:
        message = self.messages.items.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:  # type: ignore[union-attr]
            bucket = self._messages_by_project.get(message.project_id)  # type: ignore[union-attr]
            if bucket is not None and message_id in bucket:
                bucket.remove(message_id)
        if message.task_id is not None:  # type: ignore[union-attr]
            bucket = self._messages_by_task.get(message.task_id)  # type: ignore[union-attr]
            if bucket is not None and message_id in bucket:
                bucket.remove(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def _assignee_tasks(self, user_id: int) -> List[Task]:
        return [
            self.tasks.items[tid]  # type: ignore[misc]
            for tid in self._tasks_by_assignee.get(user_id, set())
        ]

    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assignee_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            return self._average_completion_time(self._assignee_tasks(user_id))

    @staticmethod
    def _average_completion_time(tasks: List[Task]) -> Optional[float]:
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        if not durations:
            return None
        return sum(durations) / len(durations)

    def submit_rating(
        self, rater_id, ratee_id, score, feedback=None, task_id=None
    ) -> Rating:
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer 1-5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)

            rating_id = self._gen_id()
            rating = Rating(
                rating_id,
                rater_id,
                ratee_id,
                score,
                feedback,
                task_id,
                self._now(),
            )
            self.performance.items[rating_id] = rating
            self._ratings_by_ratee.setdefault(ratee_id, []).append(rating_id)
            return rating.clone()

    def _ratee_ratings(self, user_id: int) -> List[Rating]:
        return [
            self.performance.items[rid]  # type: ignore[misc]
            for rid in self._ratings_by_ratee.get(user_id, [])
        ]

    def get_ratings_summary(self, user_id) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratee_ratings(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [r.clone() for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assignee_tasks(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            ratings = self._ratee_ratings(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id) -> Dict[str, object]:
        with self._lock:
            self._require_project(project_id)
            tasks = [
                self.tasks.items[tid]  # type: ignore[misc]
                for tid in self._tasks_by_project.get(project_id, set())
            ]
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            now = self._now()
            overdue = sum(
                1
                for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )
            per_assignee: Dict[int, Dict[str, object]] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                row = per_assignee.setdefault(
                    task.assignee_id,
                    {"total": 0, "completed": 0},
                )
                row["total"] += 1  # type: ignore[operator]
                if task.status == TaskStatus.COMPLETED:
                    row["completed"] += 1  # type: ignore[operator]
            for row in per_assignee.values():
                total_for_user = row["total"]  # type: ignore[index]
                row["completion_rate"] = (
                    row["completed"] / total_for_user  # type: ignore[operator]
                    if total_for_user
                    else 0.0
                )
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> Dict[str, object]:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                user_ids = set()
                for tid in self._tasks_by_project.get(project_id, set()):
                    task = self.tasks.items[tid]
                    if task.assignee_id is not None:  # type: ignore[union-attr]
                        user_ids.add(task.assignee_id)  # type: ignore[union-attr]
            else:
                user_ids = {
                    uid
                    for uid, bucket in self._tasks_by_assignee.items()
                    if bucket
                }

            rows = [
                self._performance_row(uid, project_id)
                for uid in sorted(user_ids)
            ]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def _performance_row(
        self, user_id: int, project_id: Optional[int]
    ) -> Dict[str, object]:
        task_ids = self._tasks_by_assignee.get(user_id, set())
        tasks = [self.tasks.items[tid] for tid in task_ids]  # type: ignore[misc]
        if project_id is not None:
            tasks = [t for t in tasks if t.project_id == project_id]
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        ratings = self._ratee_ratings(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count
            if rating_count
            else 0.0
        )
        return {
            "user_id": user_id,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completed / total if total else 0.0,
            "average_completion_time": self._average_completion_time(tasks),
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def individual_performance_report(self, user_id) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            task_ids = sorted(self._tasks_by_assignee.get(user_id, set()))
            tasks = [self.tasks.items[tid] for tid in task_ids]  # type: ignore[misc]
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            ratings = self._ratee_ratings(user_id)
            rating_count = len(ratings)
            rating_average = (
