                    "task_id": t.id,
                    "project_id": t.project_id,
                    "title": t.title,
                    "status": t.status.value,
                    "deadline": t.deadline.isoformat() if t.deadline else None,
                    "started_at": t.started_at.isoformat()
                    if t.started_at
                    else None,
                    "completed_at": t.completed_at.isoformat()
