    def export_report(self, report, report_format) -> object:
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dictionary")
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")
            if report_format == ReportFormat.CSV:
                return self._report_to_csv(report)
            return self._report_to_pdf(report)

    # -- export helpers -----------------------------------------------------
    @staticmethod
    def _csv_cell(value: object) -> str:
        if value is None:
            return ""
        if isinstance(value, (dict, list)):
            return json.dumps(value, default=str, sort_keys=True)
        if isinstance(value, Enum):
            return str(value.value)
        return str(value)

    def _report_to_csv(self, report: Dict[str, object]) -> str:
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")
        if isinstance(rows, list):
            if rows and isinstance(rows[0], dict):
                fieldnames = list(rows[0].keys())
            else:
                fieldnames = [
                    "user_id",
                    "total_tasks",
                    "completed_tasks",
                    "completion_rate",
                    "average_completion_time",
                    "rating_count",
                    "rating_average",
                ]
            writer.writerow(fieldnames)
            for row in rows:
                if isinstance(row, dict):
                    writer.writerow(
                        [self._csv_cell(row.get(name)) for name in fieldnames]
                    )
                else:
                    writer.writerow([self._csv_cell(row)])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, self._csv_cell(value)])
        return output.getvalue()

    def _report_to_pdf(self, report: Dict[str, object]) -> bytes:
        return self._build_pdf(self._report_to_lines(report))

    @staticmethod
    def _report_to_lines(report: Dict[str, object]) -> List[str]:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if key == "rows" and isinstance(value, list):
                lines.append("rows:")
                for row in value:
                    if isinstance(row, dict):
                        lines.append(
                            "  "
                            + ", ".join(
                                "{0}={1}".format(k, v) for k, v in row.items()
                            )
                        )
                    else:
                        lines.append("  {0}".format(row))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines

    @staticmethod
    def _build_pdf(lines: List[str]) -> bytes:
        def escape(text: str) -> str:
            return (
                text.replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )

        content_parts = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
        first = True
        for line in lines or [""]:
            safe = escape(str(line))
            if first:
                content_parts.append("({0}) Tj".format(safe))
                first = False
            else:
                content_parts.append("T*")
                content_parts.append("({0}) Tj".format(safe))
        content_parts.append("ET")
        content = "\n".join(content_parts).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>",
            b"<< /Length "
            + str(len(content)).encode("ascii")
            + b" >>\nstream\n"
            + content
            + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets: List[int] = []
        for index, obj in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += str(index).encode("ascii") + b" 0 obj\n" + obj + b"\nendobj\n"

        xref_pos = len(pdf)
        size = len(objects) + 1
        pdf += b"xref\n0 " + str(size).encode("ascii") + b"\n"
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += (
            b"trailer\n<< /Size "
            + str(size).encode("ascii")
            + b" /Root 1 0 R >>\nstartxref\n"
            + str(xref_pos).encode("ascii")
            + b"\n%%EOF"
        )
        return bytes(pdf)


